css:
@page {
  size: A4 landscape;
}

.table_info tbody tr td,
.table_main_content tbody tr td {
    padding-left: 0!important;
    padding-bottom: 0!important;
    padding-top: 0!important;
    white-space: normal;     
    word-break: break-word; 
    overflow-wrap: break-word;
}

.table_main_content {
    width: 100%!important;
}

.table_main_content tbody tr td {
    border: 1px solid #000;
}
